def evaluate_expression(expression):
    def is_operator(ch):
        return ch in ['+', '-', '*', '/']

    def precedence(op):
        return 2 if op in ('*', '/') else 1

    if not isinstance(expression, str):
        raise TypeError("expression must be a string")

    s = expression.replace(" ", "")
    if s == "":
        raise ValueError("empty expression")

    for ch in s:
        if not (ch.isdigit() or is_operator(ch)):
            raise ValueError("invalid character")

    values = []
    ops = []
    expect_number = True  # grammar: number (op number)*

    def apply_top():
        op = ops.pop()
        b = values.pop()
        a = values.pop()
        if op == '+':
            values.append(a + b)
        elif op == '-':
            values.append(a - b)
        elif op == '*':
            values.append(a * b)
        elif op == '/':
            if b == 0:
                raise ZeroDivisionError("division by zero")
            values.append(a / b)
        else:
            raise ValueError("invalid operator")

    for ch in s:
        if ch.isdigit():
            if not expect_number:
                raise ValueError("malformed expression")
            values.append(float(ch))
            expect_number = False
        else:
            if expect_number:
                raise ValueError("malformed expression")
            while ops and precedence(ops[-1]) >= precedence(ch):
                apply_top()
            ops.append(ch)
            expect_number = True

    if expect_number:
        raise ValueError("malformed expression")

    while ops:
        if len(values) < 2:
            raise ValueError("malformed expression")
        apply_top()

    if len(values) != 1:
        raise ValueError("malformed expression")
    return values[0]

