import re

def filter_rows(rows, predicate):
    if not isinstance(rows, list):
        raise TypeError("rows must be a list")
    if not isinstance(predicate, str):
        raise TypeError("predicate must be a string")

    for row in rows:
        if not isinstance(row, dict):
            raise TypeError("each row must be a dict")
        for k, v in row.items():
            if not isinstance(k, str):
                raise TypeError("row keys must be strings")
            if not (v is None or isinstance(v, (str, int, float, bool))):
                raise TypeError("row values must be primitive types")

    m = re.fullmatch(
        r'\s*([A-Za-z_][A-Za-z0-9_]*)\s*(==|!=|>=|<=|>|<)\s*(?:(-?(?:\d+(?:\.\d*)?|\.\d+))|"([^"\\]*(?:\\.[^"\\]*)*)")\s*\Z',
        predicate
    )
    if not m:
        raise ValueError("invalid predicate format")

    field = m.group(1)
    op = m.group(2)
    num_s = m.group(3)
    str_s = m.group(4)

    if num_s is not None:
        try:
            value = float(num_s)
            value_is_number = True
        except Exception as e:
            raise ValueError("invalid numeric value") from e
    else:
        # unescape common sequences in a controlled way
        try:
            value = bytes(str_s, "utf-8").decode("unicode_escape")
        except Exception as e:
            raise ValueError("invalid string literal") from e
        value_is_number = False

    def cmp(a, b):
        if op == "==": return a == b
        if op == "!=": return a != b
        if op == ">":  return a > b
        if op == ">=": return a >= b
        if op == "<":  return a < b
        if op == "<=": return a <= b
        raise ValueError("invalid operator")

    out = []
    for row in rows:
        if field not in row:
            raise ValueError("unknown field")

        cell = row[field]
        if value_is_number:
            if not isinstance(cell, (int, float)):
                raise TypeError("field value must be numeric for numeric comparisons")
            if cmp(float(cell), float(value)):
                out.append(row)
        else:
            if not isinstance(cell, str):
                raise TypeError("field value must be string for string comparisons")
            if cmp(cell, value):
                out.append(row)

    return out

