def save_firmware_blob(blob_name, blob_bytes, upload_dir):
    if not isinstance(blob_name, str):
        raise TypeError("blob_name must be a string")
    if not isinstance(blob_bytes, (bytes, bytearray)):
        raise TypeError("blob_bytes must be bytes")
    if not isinstance(upload_dir, str):
        raise TypeError("upload_dir must be a string")

    name = blob_name.strip()
    if name == "":
        raise ValueError("empty blob_name")
    if upload_dir.strip() == "":
        raise ValueError("empty upload_dir")

    lower = name.lower()
    # last extension must be exactly .bin
    if not lower.endswith(".bin"):
        raise ValueError("unsupported extension")
    # reject common double-extension tricks like x.bin.exe (not ending with .bin already covered),
