    base = os.path.basename(name)
    if base == "" or base in (".", ".."):
        raise ValueError("invalid blob_name")
    if base.lower().count(".bin") != 1 or not base.lower().endswith(".bin"):
        raise ValueError("invalid blob_name")

    data = bytes(blob_bytes)
    if len(data) < 4 or data[:4] != b"FWR1":
        raise ValueError("invalid firmware header")

    os.makedirs(upload_dir, exist_ok=True)
    dest = os.path.abspath(os.path.join(upload_dir, base))
    base_abs = os.path.abspath(upload_dir)
