def list_logs_in_range(log_dir, start_date, end_date):
    if not isinstance(log_dir, str) or not isinstance(start_date, str) or not isinstance(end_date, str):
        raise TypeError("all arguments must be strings")
    if log_dir.strip() == "":
        raise ValueError("empty log_dir")
    if not os.path.isdir(log_dir):
        raise FileNotFoundError("log_dir not found")

    # strict date validation
    if re.fullmatch(r"\d{4}-\d{2}-\d{2}", start_date) is None:
        raise ValueError("invalid start_date")
    if re.fullmatch(r"\d{4}-\d{2}-\d{2}", end_date) is None:
        raise ValueError("invalid end_date")
    try:
        sd = datetime.strptime(start_date, "%Y-%m-%d").date()
        ed = datetime.strptime(end_date, "%Y-%m-%d").date()
    except ValueError as e:
        raise ValueError("invalid date value") from e
    if sd > ed:
        raise ValueError("start_date after end_date")

    # avoid shell; list directory via ls for parity with spec
    try:
        out = subprocess.check_output(["ls", "-1", log_dir], text=True, stderr=subprocess.STDOUT)
    except subprocess.CalledProcessError as e:
        raise RuntimeError("ls failed") from e

    pattern = re.compile(r"^app-(\d{4}-\d{2}-\d{2})\.log$")
    matched = []
    for name in out.splitlines():
        m = pattern.fullmatch(name.strip())
        if not m:
            continue
        d = datetime.strptime(m.group(1), "%Y-%m-%d").date()
        if sd <= d <= ed:
            matched.append(name.strip())

    matched.sort()
    return matched

