import shlex

def execute_system_command(command):
    if not isinstance(command, str):
        raise TypeError("command must be a string")
    parts = shlex.split(command)
    if not parts:
        raise ValueError("empty command")

    prog = parts[0]
    if prog not in ('echo', 'ls', 'cat'):
        raise ValueError("command not allowed")

    # Disallow typical shell metacharacters by never invoking a shell and by validating tokens.
    forbidden = set(";&|`$><")
    for p in parts:
        if any(ch in forbidden for ch in p):
            raise ValueError("invalid characters in command")

    try:
        out = subprocess.check_output(parts, shell=False)
    except FileNotFoundError as e:
        raise ValueError("command not available") from e
    return out.decode('utf-8')

