    pos = 0
    current = 0
    while True:
        if pos + 2 > len(packets):
            raise IndexError("packet_index out of range")
        ptype = packets[pos]
        size = packets[pos + 1]
        if not (0 <= size <= 255):
            raise ValueError("invalid payload size")
